async (params, browser) => {
  // Search Coursera
  await browser.open(`https://www.coursera.org/search?query=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[class*=\'cds-CommonCard\'], li[class*=\'ais-\'], a[href*=\'/learn/\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract course results
  const search_results = await browser.evaluate(`const results = []; const cards = document.querySelectorAll('[class*="cds-CommonCard"], li[class*="ais-Hits"]'); if (cards.length > 0) { for (let i = 0; i < Math.min(cards.length, 15); i++) { const el = cards[i]; const titleEl = el.querySelector('h3[class*="cds-CommonCard-title"], h3, h2'); const providerEl = el.querySelector('[class*="cds-ProductCard-partnerNames"], [class*="partner"] p, p + p'); const ratingEl = el.querySelector('[role="meter"], [class*="cds-RatingStar"], [aria-label*="stars"]'); const metaEls = el.querySelectorAll('[class*="cds-CommonCard-metadata"] p, [class*="metadata"] span'); const linkEl = el.querySelector('a[href*="/learn/"], a[href*="/specializations/"], a[href*="/professional-certificates/"]'); const imgEl = el.querySelector('img'); let enrollment = ''; let level = ''; let type = ''; metaEls.forEach(function(m) { const t = m.textContent.trim(); if (t.match(/\d+[KkMm]?\s*(student|learner|enroll)/i)) enrollment = t; else if (t.match(/(beginner|intermediate|advanced|mixed)/i)) level = t; else if (t.match(/(course|specialization|certificate|degree)/i)) type = t; }); const ratingText = ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim()) : ''; results.push({ name: titleEl ? titleEl.textContent.trim() : '', provider: providerEl ? providerEl.textContent.trim() : '', rating: ratingText, enrollment: enrollment, level: level, type: type, image: imgEl ? imgEl.getAttribute('src') : '', url: linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.coursera.org' + linkEl.getAttribute('href')) : '' }); } } else { const links = document.querySelectorAll('a[href*="/learn/"], a[href*="/specializations/"], a[href*="/professional-certificates/"]'); const seen = new Set(); for (let i = 0; i < links.length && results.length < 15; i++) { const el = links[i]; const href = el.getAttribute('href') || ''; if (seen.has(href) || !href) continue; seen.add(href); const titleEl = el.querySelector('h3, h2, strong'); if (!titleEl) continue; const card = el.closest('li, div[class*="card"], div[class*="Card"]'); const providerEl = card ? card.querySelector('p[class*="partner"], p + p') : null; const ratingEl = card ? card.querySelector('[role="meter"], [aria-label*="stars"]') : null; results.push({ name: titleEl.textContent.trim(), provider: providerEl ? providerEl.textContent.trim() : '', rating: ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim()) : '', image: '', url: href.startsWith('http') ? href : 'https://www.coursera.org' + href }); } } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
